spec.rawSql:
SELECT fetched_at AS "time", category, mbps
    FROM velop.v_wifi_vs_wired
    WHERE t_ms BETWEEN ${__from} AND ${__to}
    ORDER BY 1 ASC, 2 ASC;

SELECT fetched_at AS "time", metric, tx_mbps
FROM velop.v_radio_rates
WHERE t_ms BETWEEN ${__from} AND ${__to}
AND metric like '%'||'$wifi_types'
ORDER BY 1 ASC;

SELECT fetched_at AS "time", intf, rx_mbps, tx_mbps
FROM velop.v_nic_rates
WHERE t_ms BETWEEN ${__from} AND ${__to}
ORDER BY 1 ASC;

SELECT fetched_at AS "time", node, wifi_mbps
FROM velop.v_node_wifi_rates
WHERE t_ms BETWEEN ${__from} AND ${__to}
ORDER BY 1 ASC, 2 ASC;

SELECT fetched_at,   sum(self_bss_util)  AS "Us", sum(obss_util) AS  "Them", sum(tx_fail_pct) AS tx_fail_pct
FROM velop.v_radio_rates
WHERE    t_ms BETWEEN ${__from} AND ${__to}
AND  metric  LIKE '%$wifi_types'
GROUP BY fetched_at;
